previewCss:
.darma-loader-darma-custom-440 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
   width: 65px;
   display: grid;
   --mask: radial-gradient(12px at left 15px top 50%, #0000 95%, currentColor), radial-gradient(12px at right 15px top 50%, #0000 95%, currentColor);
   -webkit-mask: var(--mask);
   mask: var(--mask);
   -webkit-mask-composite: source-in;
   mask-composite: intersect;
   animation: darma-loader-darma-custom-440-l1 1s infinite alternate;
}
.darma-loader-darma-custom-440:before, .darma-loader-darma-custom-440:after  {
  content: "";
   grid-area: 1/1;
   height: 30px;
   aspect-ratio: 1;
   background: currentColor;
   border-radius: 50%;
}
.darma-loader-darma-custom-440:after  {
  margin-left: auto;
}
@keyframes darma-loader-darma-custom-440-l1  {
  to  {
  width: 40px;
}
}

